{{!-- ===== Query params with defaults/coercion ===== --}}
{{setVar 'pageSize'        (parseInt (queryParamRaw 'Size' '25'))}}
{{setVar 'page'            (parseInt (queryParamRaw 'Page' '1'))}}
{{setVar 'historyDays'     (parseInt (queryParamRaw 'historyDays' '365'))}}
{{setVar 'seedDate'        (queryParamRaw 'date' '')}}

{{!-- Specific filters (single-value only; MCP should send one value) --}}
{{setVar 'companyFilter'   (queryParamRaw 'searchCompanyName' '')}}
{{setVar 'methodFilter'    (queryParamRaw 'searchBackupMethod' '')}}
{{setVar 'jobFilter'       (queryParamRaw 'searchJobName' '')}}
{{setVar 'deviceFilter'    (queryParamRaw 'searchDeviceName' '')}}
{{setVar 'tagFilter'       (queryParamRaw 'searchTag' '')}}
{{setVar 'tooltipFilter'   (queryParamRaw 'searchTooltip' '')}}
{{setVar 'statusFilter'    (queryParamRaw 'statuses' '')}}      {{!-- single status value --}}
{{setVar 'filterScheduled' (queryParamRaw 'filterScheduled' '')}}
{{setVar 'daysNoSuccess'   (queryParamRaw 'daysWithoutSuccess' '')}}
{{setVar 'policyIdRaw'     (queryParamRaw 'policyIds' '')}}     {{!-- single id (if multiple, MCP should send the first) --}}

{
  "Total": {{int 1 99999}},
  "Page": {{getVar 'page'}},
  "PageSize": {{getVar 'pageSize'}},
  "TotalPages": {{int 1 500}},
  "Results": [
    {{#repeat (getVar 'pageSize')}}
      {{!-- ===== per-row resolved values (choose filter OR faker) ===== --}}

      {{!-- Company --}}
      {{#if (getVar 'companyFilter')}}
        {{setVar 'rowCompany' (getVar 'companyFilter')}}
      {{else}}
        {{setVar 'rowCompany' (faker 'company.name')}}
      {{/if}}

      {{!-- Method --}}
      {{#if (getVar 'methodFilter')}}
        {{setVar 'rowMethod' (getVar 'methodFilter')}}
      {{else}}
        {{setVar 'rowMethod' (faker 'helpers.arrayElement' (array 'Veeam' 'Datto' 'AWS' 'Altaro' 'BackupExec' 'Windows Backups' 'Replibit API'))}}
      {{/if}}

      {{!-- Device --}}
      {{#if (getVar 'deviceFilter')}}
        {{setVar 'rowDevice' (getVar 'deviceFilter')}}
      {{else}}
        {{setVar 'rowDevicePrefix' (faker 'hacker.abbreviation')}}
        {{setVar 'rowDeviceNum' (int 10 99)}}
      {{/if}}

      {{!-- Job --}}
      {{#if (getVar 'jobFilter')}}
        {{setVar 'rowJob' (getVar 'jobFilter')}}
      {{else}}
        {{setVar 'rowJobNoun' (faker 'word.noun')}}
        {{setVar 'rowJobAdj'  (faker 'word.adjective')}}
      {{/if}}

      {{!-- Device type --}}
      {{setVar 'rowDeviceType' (faker 'helpers.arrayElement' (array 'Server' 'Workstation'))}}

      {{!-- Status (single filter value if provided) --}}
      {{#if (getVar 'statusFilter')}}
        {{setVar 'rowStatusName' (getVar 'statusFilter')}}
      {{else}}
        {{setVar 'rowStatusName' (faker 'helpers.arrayElement' (array 'Success' 'Warning' 'Failure' 'No Result'))}}
      {{/if}}

      {{!-- Backup type: id + matching name --}}
      {{setVar 'rowBackupTypeId' (faker 'helpers.arrayElement' (array 0 1))}}
      {{#if (eq (getVar 'rowBackupTypeId') 1)}}
        {{setVar 'rowBackupTypeName' 'Alert'}}
      {{else}}
        {{setVar 'rowBackupTypeName' 'Backup'}}
      {{/if}}

      {{!-- Tags: ensure searchTag is present if provided; total extra tags 0..2 --}}
      {{#if (getVar 'tagFilter')}}
        {{setVar 'rowExtraTags' (int 0 2)}}  {{!-- we will prepend the filter tag --}}
      {{else}}
        {{setVar 'rowExtraTags' (int 0 3)}}
      {{/if}}

      {{!-- Scheduled flag: treat "true" (string) as true --}}
      {{#if (eq (getVar 'filterScheduled') 'true')}}
        {{setVar 'rowForceScheduled' 'true'}}
      {{else}}
        {{setVar 'rowForceScheduled' ''}}
      {{/if}}

      {{!-- Days without success: numeric if provided --}}
      {{#if (getVar 'daysNoSuccess')}}
        {{setVar 'rowDaysNoSuccess' (parseInt (getVar 'daysNoSuccess'))}}
      {{else}}
        {{setVar 'rowDaysNoSuccess' ''}}
      {{/if}}

      {{!-- BackupId: try to parse provided; else random --}}
      {{#if (getVar 'policyIdRaw')}}
        {{setVar 'rowBackupId' (parseInt (getVar 'policyIdRaw'))}}
      {{else}}
        {{setVar 'rowBackupId' (int 1 99999)}}
      {{/if}}

      {{!-- Dates: use seed date for lastResult if given --}}
      {{#if (getVar 'seedDate')}}
        {{setVar 'rowLastResult' (getVar 'seedDate')}}
      {{else}}
        {{setVar 'rowLastResult' (faker 'date.recent' days=(getVar 'historyDays'))}}
      {{/if}}
      {{setVar 'rowLastSuccess' (faker 'date.recent' days=(getVar 'historyDays'))}}

    {
      "ticketingCompany": "{{getVar 'rowCompany'}}",

      "status": {
        "id": {{int 1 99999}},
        "name": "{{getVar 'rowStatusName'}}"
      },

      "daysInStatus": {{float 0 365 2}},
      "isVerified": {{faker 'datatype.boolean'}},
      "lastResult": "{{getVar 'rowLastResult'}}",
      "lastSuccess": "{{getVar 'rowLastSuccess'}}",
      "ticketCount": {{int 0 99999}},
      "failureThreshold": {{float 0 10 1}},
      "treatWarningAsSuccess": {{faker 'datatype.boolean'}},

      "note": {{#if (getVar 'tooltipFilter')}}
                "{{getVar 'tooltipFilter'}}"
              {{else}}
                {{#if (faker 'datatype.boolean')}} "{{faker 'hacker.phrase'}}" {{else}} null {{/if}}
              {{/if}},

      "dayStartHour": {{int 0 23}},

      "tags": [
        {{#if (getVar 'tagFilter')}}
          "{{getVar 'tagFilter'}}"{{#if (gt (getVar 'rowExtraTags') 0)}},{{/if}}
        {{/if}}
        {{#repeat (getVar 'rowExtraTags')}}
          "{{faker 'helpers.arrayElement' (array 'Veeam' 'Datto' 'AWS' 'Altaro' 'Important' 'Ignore')}}"
          {{#unless @last}},{{/unless}}
        {{/repeat}}
      ],

      "standalone": {{faker 'datatype.boolean'}},

      "history": [
        {{#repeat (int 0 3)}}
        {
          "status": {
            "id": {{int 1 99999}},
            "name": "{{#if (getVar 'statusFilter')}}{{getVar 'statusFilter'}}{{else}}{{faker 'helpers.arrayElement' (array 'Success' 'Warning' 'Failure' 'No Result')}}{{/if}}"
          },
          "lastResultDate": "{{faker 'date.recent' days=(getVar 'historyDays')}}",
          "isScheduled": {{#if (getVar 'rowForceScheduled')}}true{{else}}{{faker 'datatype.boolean'}}{{/if}},
          "daysInStatus": {{float 0 365 1}},
          "date": "{{faker 'date.recent' days=(getVar 'historyDays')}}",
          "countFailure": {{int 0 99999}},
          "countWarning": {{int 0 99999}},
          "countSuccess": {{int 0 99999}},
          "countNoResult": {{int 0 99999}},
          "daysSinceLastResult": {{float 0 365 1}},
          "daysSinceLastGoodResult": {{#if (getVar 'rowDaysNoSuccess')}}{{getVar 'rowDaysNoSuccess'}}{{else}}{{float -1 365 1}}{{/if}},
          "resultsCount": {{int 0 99999}}
        }{{#unless @last}},{{/unless}}
        {{/repeat}}
      ],

      "backupId": {{getVar 'rowBackupId'}},

      "companyName": "{{getVar 'rowCompany'}}",
      "deviceName": "{{#if (getVar 'deviceFilter')}}{{getVar 'rowDevice'}}{{else}}{{getVar 'rowDevicePrefix'}}-{{getVar 'rowDeviceNum'}}{{/if}}",
      "deviceType": "{{getVar 'rowDeviceType'}}",
      "jobName": "{{#if (getVar 'jobFilter')}}{{getVar 'rowJob'}}{{else}}{{getVar 'rowJobNoun'}} {{getVar 'rowJobAdj'}} Report{{/if}}",
      "methodName": "{{getVar 'rowMethod'}}",

      "backupType": {
        "id": {{getVar 'rowBackupTypeId'}},
        "name": "{{getVar 'rowBackupTypeName'}}"
      }
    }{{#unless @last}},{{/unless}}
    {{/repeat}}
  ]
}

{
  "ticketingCompany": "{{faker 'company.name'}}",
  "status": {
    "id": {{faker 'number.int' min=1 max=99999}},
    "name": "{{faker 'helpers.arrayElement' (array 'Success' 'Warning' 'Failure' 'No Result')}}"
  },
  "daysInStatus": {{faker 'number.float' min=0 max=365 precision=0.01}},
  "isVerified": {{faker 'helpers.arrayElement' (array true false)}},
  "lastResult": "{{faker 'date.recent' days=365}}",
  "lastSuccess": "{{faker 'date.recent' days=365}}",
  "ticketCount": {{faker 'number.int' min=0 max=99999}},
  "failureThreshold": {{faker 'number.float' min=0 max=10 precision=0.1}},
  "treatWarningAsSuccess": {{faker 'helpers.arrayElement' (array true false)}},
  "note": {{#if (faker 'helpers.arrayElement' (array true false))}}"{{faker 'hacker.phrase'}}"{{else}}null{{/if}},
  "dayStartHour": {{faker 'number.int' min=0 max=23}},
  "tags": [{{#repeat (faker 'number.int' min=0 max=3)}}"{{faker 'helpers.arrayElement' (array 'Veeam' 'Datto' 'AWS' 'Altaro' 'Important' 'Ignore')}}"{{/repeat}}],
  "standalone": {{faker 'helpers.arrayElement' (array true false)}},
  "history": [
    {{#repeat (faker 'number.int' min=0 max=3)}}
    {
      "status": {
        "id": {{faker 'number.int' min=1 max=99999}},
        "name": "{{faker 'helpers.arrayElement' (array 'Success' 'Warning' 'Failure' 'No Result')}}"
      },
      "lastResultDate": "{{faker 'date.recent' days=365}}",
      "isScheduled": {{faker 'helpers.arrayElement' (array true false)}},
      "daysInStatus": {{faker 'number.float' min=0 max=365 precision=0.1}},
      "date": "{{faker 'date.recent' days=365}}",
      "countFailure": {{faker 'number.int' min=0 max=99999}},
      "countWarning": {{faker 'number.int' min=0 max=99999}},
      "countSuccess": {{faker 'number.int' min=0 max=99999}},
      "countNoResult": {{faker 'number.int' min=0 max=99999}},
      "daysSinceLastResult": {{faker 'number.float' min=0 max=365 precision=0.1}},
      "daysSinceLastGoodResult": {{faker 'number.float' min=-1 max=365 precision=0.1}},
      "resultsCount": {{faker 'number.int' min=0 max=99999}}
    }{{#unless @last}},{{/unless}}
    {{/repeat}}
  ],
  "backupId": {{#if (urlParam 'backupId')}}{{urlParam 'backupId'}}{{else}}{{faker 'number.int' min=1 max=99999}}{{/if}},
  "companyName": "{{faker 'company.name'}}",
  "deviceName": "{{faker 'hacker.abbreviation'}}-{{faker 'number.int' min=10 max=99}}",
  "deviceType": "{{faker 'helpers.arrayElement' (array 'Server' 'Workstation')}}",
  "jobName": "{{faker 'word.noun'}} {{faker 'word.adjective'}} Report",
  "methodName": "{{faker 'helpers.arrayElement' (array 'Veeam' 'Datto' 'AWS' 'Altaro' 'BackupExec' 'Windows Backups' 'Replibit API')}}",
  "backupType": {
    "id": {{faker 'helpers.arrayElement' (array 0 1)}},
    "name": "{{faker 'helpers.arrayElement' (array 'Backup' 'Alert')}}"
  }
}

{
  "Total": {{faker 'number.int' max=99999}},
  "Page": {{faker 'number.int' max=99999}},
  "PageSize": {{faker 'number.int' max=99999}},
  "TotalPages": {{faker 'number.int' max=99999}},
  "Results": [
    {
      "dateTime": "{{faker 'date.recent' 365}}",
      "success": {{faker 'datatype.boolean'}},
      "warning": {{faker 'datatype.boolean'}},
      "failure": {{faker 'datatype.boolean'}},
      "manual": {{faker 'datatype.boolean'}},
      "resultId": {{faker 'number.int' min=1 max=99999}}
    }
  ]
}
